{
  "name": "activtrak-mcp-sandbox",
  "version": "1.0.0",
  "description": "Code Mode sandbox MCP server — exposes search_tools + execute_code for Cursor, Windsurf, Gemini, Codex",
  "type": "module",
  "main": "dist/index.js",
  "scripts": {
    "build": "tsc",
    "start": "node dist/index.js",
    "dev": "tsc --watch"
  },
  "dependencies": {
    "@modelcontextprotocol/sdk": "^1.10.0"
  },
  "devDependencies": {
    "@types/node": "^22.0.0",
    "typescript": "^5.7.0"
  },
  "engines": {
    "node": ">=20"
  }
}

import { Client } from "@modelcontextprotocol/sdk/client/index.js";
import { StdioClientTransport } from "@modelcontextprotocol/sdk/client/stdio.js";
import type { Tool } from "@modelcontextprotocol/sdk/types.js";
import { readFileSync } from "fs";
import { join } from "path";

interface StdioServerConfig {
  type?: "stdio";
  command: string;
  args?: string[];
  env?: Record<string, string>;
}

interface McpConfig {
  mcpServers: Record<string, StdioServerConfig>;
}

export class ToolBridge {
  private clients: Map<string, Client> = new Map();
  private toolDefs: Tool[] = [];
  private toolServerMap: Map<string, string> = new Map();

  async connect(): Promise<void> {
    // Resolve config relative to project root (two levels up from tools/mcp-sandbox/)
    const projectRoot = join(new URL(import.meta.url).pathname, "..", "..", "..", "..");
    const configPath = join(projectRoot, ".cursor", "mcp.json");

    let config: McpConfig = { mcpServers: {} };
    try {
      config = JSON.parse(readFileSync(configPath, "utf-8")) as McpConfig;
    } catch {
      process.stderr.write(`[sandbox] No .cursor/mcp.json found at ${configPath}; starting with no tools.\n`);
    }

    for (const [serverName, serverConfig] of Object.entries(config.mcpServers)) {
      // Skip self to avoid recursion
      if (serverName === "activtrak-sandbox") continue;
      // Skip remote (HTTP/SSE) servers — only stdio is supported for bridging
      if (!serverConfig.command) continue;

      try {
        const client = new Client(
          { name: "sandbox-bridge", version: "1.0.0" },
          { capabilities: {} }
        );
        const transport = new StdioClientTransport({
          command: serverConfig.command,
          args: serverConfig.args ?? [],
          env: { ...process.env as Record<string, string>, ...(serverConfig.env ?? {}) },
        });
        await client.connect(transport);
        this.clients.set(serverName, client);

        const { tools } = await client.listTools();
        for (const tool of tools) {
          const namespacedName = `${serverName}__${tool.name}`;
          this.toolDefs.push({ ...tool, name: namespacedName });
          this.toolServerMap.set(namespacedName, serverName);
        }
        process.stderr.write(`[sandbox] Connected to ${serverName} (${tools.length} tools)\n`);
      } catch (err) {
        process.stderr.write(`[sandbox] Failed to connect to ${serverName}: ${String(err)}\n`);
      }
    }
  }

  getToolDefs(): Tool[] {
    return this.toolDefs;
  }

  async callTool(namespacedName: string, args: Record<string, unknown>): Promise<unknown> {
    const serverName = this.toolServerMap.get(namespacedName);
    if (!serverName) throw new Error(`Unknown tool: ${namespacedName}`);

    const client = this.clients.get(serverName);
    if (!client) throw new Error(`Server not connected: ${serverName}`);

    const originalName = namespacedName.slice(serverName.length + 2); // strip "serverName__"
    const result = await client.callTool({ name: originalName, arguments: args });
    return result;
  }

  async disconnectAll(): Promise<void> {
    for (const client of this.clients.values()) {
      await client.close();
    }
  }
}

import vm from "vm";
import type { ToolBridge } from "./bridge.js";

const TIMEOUT_MS = 30_000;

/**
 * Executes agent-generated TypeScript code in a restricted Node.js vm context.
 *
 * The sandbox provides:
 *   - `tools.<server>__<tool>(args)` — async functions that proxy to real MCP servers
 *   - Standard globals: Promise, JSON, Math, Date, Array, Object, String, Number, Boolean
 *
 * The sandbox denies:
 *   - File system access (no `fs`, `require`, `import`)
 *   - Network access (no `fetch`, `http`, `https`)
 *   - Process control (no `process.exit`, `process.env`)
 *
 * Only the return value of the script surfaces to the LLM context. All intermediate
 * tool responses stay inside the sandbox, which is the key token-reduction mechanism.
 */
export async function runInSandbox(code: string, bridge: ToolBridge): Promise<string> {
  // Wire each tool as an async function using a safe name (hyphens → underscores)
  const tools: Record<string, (args: unknown) => Promise<unknown>> = {};
  for (const tool of bridge.getToolDefs()) {
    const safeName = tool.name.replace(/-/g, "_");
    tools[safeName] = (args) =>
      bridge.callTool(tool.name, args as Record<string, unknown>);
  }

  const context = vm.createContext({
    tools,
    // Safe subset of globals — no fs, net, process, require, or import
    console: {
      log: (...args: unknown[]) => process.stderr.write(args.join(" ") + "\n"),
      error: (...args: unknown[]) => process.stderr.write(args.join(" ") + "\n"),
    },
    Promise,
    JSON,
    Math,
    Date,
    Array,
    Object,
    String,
    Number,
    Boolean,
    parseInt,
    parseFloat,
    isNaN,
    isFinite,
  });

  // Wrap in async IIFE so the agent code can use top-level `await`
  const wrapped = `(async () => {\n${code}\n})()`;

  let script: vm.Script;
  try {
    script = new vm.Script(wrapped, { filename: "sandbox.ts" });
  } catch (err) {
    throw new Error(`Sandbox syntax error: ${String(err)}`);
  }

  const result = await Promise.race([
    script.runInContext(context) as Promise<unknown>,
    new Promise<never>((_, reject) =>
      setTimeout(
        () => reject(new Error(`Sandbox timed out after ${TIMEOUT_MS / 1000}s`)),
        TIMEOUT_MS
      )
    ),
  ]);

  return String(result ?? "");
}

import { Server } from "@modelcontextprotocol/sdk/server/index.js";
import { StdioServerTransport } from "@modelcontextprotocol/sdk/server/stdio.js";
import {
  CallToolRequestSchema,
  ListToolsRequestSchema,
} from "@modelcontextprotocol/sdk/types.js";
import { ToolBridge } from "./bridge.js";
import { runInSandbox } from "./runner.js";

const bridge = new ToolBridge();
await bridge.connect();

const server = new Server(
  { name: "activtrak-sandbox", version: "1.0.0" },
  { capabilities: { tools: {} } }
);

server.setRequestHandler(ListToolsRequestSchema, async () => ({
  tools: [
    {
      name: "search_tools",
      description:
        "Search for available MCP tools by keyword. Returns tool names and descriptions. " +
        "Call this first to discover which tools are relevant before using execute_code. " +
        "Returns up to 8 matches.",
      inputSchema: {
        type: "object" as const,
        properties: {
          query: {
            type: "string",
            description: "Keyword or natural language description of what you want to do",
          },
        },
        required: ["query"],
      },
    },
    {
      name: "execute_code",
      description:
        "Execute TypeScript code in a sandboxed environment. " +
        "All MCP tools are pre-wired as async functions on `tools` " +
        "(e.g. `await tools.serena__find_symbol({ name: 'Tracker' })`). " +
        "Hyphens in tool names are replaced with underscores. " +
        "IMPORTANT: return a concise string summary — this is the ONLY thing returned to the LLM context. " +
        "Raw tool responses stay inside the sandbox. Use this for any task requiring 2+ tool calls.",
      inputSchema: {
        type: "object" as const,
        properties: {
          code: {
            type: "string",
            description:
              "TypeScript code to execute. Use `await tools.server__toolname(args)` to call tools. " +
              "Must return a string (or a value that converts to one).",
          },
        },
        required: ["code"],
      },
    },
  ],
}));

server.setRequestHandler(CallToolRequestSchema, async (req) => {
  const { name, arguments: args } = req.params;

  if (name === "search_tools") {
    const query = ((args as { query: string }).query ?? "").toLowerCase();
    const defs = bridge.getToolDefs();
    const matches = defs.filter(
      (t) =>
        t.name.toLowerCase().includes(query) ||
        (t.description ?? "").toLowerCase().includes(query)
    );
    const top = matches.slice(0, 8);
    const text =
      top.length > 0
        ? top.map((t) => `- ${t.name}: ${t.description ?? "(no description)"}`).join("\n")
        : `No tools found matching "${query}". Available servers: ${[...new Set(defs.map((t) => t.name.split("__")[0]))].join(", ")}`;
    return { content: [{ type: "text", text }] };
  }

  if (name === "execute_code") {
    const code = (args as { code: string }).code ?? "";
    try {
      const result = await runInSandbox(code, bridge);
      return { content: [{ type: "text", text: result }] };
    } catch (err) {
      return {
        content: [{ type: "text", text: `Sandbox error: ${String(err)}` }],
        isError: true,
      };
    }
  }

  return {
    content: [{ type: "text", text: `Unknown tool: ${name}` }],
    isError: true,
  };
});

process.on("SIGINT", async () => {
  await bridge.disconnectAll();
  process.exit(0);
});

const transport = new StdioServerTransport();
await server.connect(transport);
